# -*- coding: utf-8 -*-
import csv

questions = [
  {"id":"4309","tipo":"multipla","disciplina":"Matematica","tema":"Algebra","subtema":"Produto de soma e diferenca","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"O resultado de (5+3)(5-3) e:","alternativa_a":"16","alternativa_b":"64","alternativa_c":"6","alternativa_d":"4","alternativa_e":"30","resposta_correta":"a","explicacao":"(a+b)(a-b) = a^2 - b^2 = 25 - 9 = 16.","resposta":""},
  {"id":"4310","tipo":"multipla","disciplina":"Matematica","tema":"Geometria Plana","subtema":"Paralelogramo","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"Um paralelogramo tem base 8 cm e altura 5 cm. Sua area e:","alternativa_a":"40 cm2","alternativa_b":"26 cm2","alternativa_c":"20 cm2","alternativa_d":"80 cm2","alternativa_e":"13 cm2","resposta_correta":"a","explicacao":"Area do paralelogramo = base x altura = 8 x 5 = 40 cm2.","resposta":""},
  {"id":"4311","tipo":"multipla","disciplina":"Matematica","tema":"Estatistica","subtema":"Variancia e desvio padrao","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"O desvio padrao mede:","alternativa_a":"A dispersao dos dados em torno da media — quanto os valores se afastam da media","alternativa_b":"O valor central do conjunto de dados","alternativa_c":"O valor que aparece com mais frequencia","alternativa_d":"A diferenca entre o maior e o menor valor","alternativa_e":"A probabilidade de cada evento","resposta_correta":"a","explicacao":"O desvio padrao (sigma) mede a dispersao dos dados em torno da media. Pequeno DP = dados concentrados perto da media. Grande DP = dados muito espalhados. Variancia = sigma^2. Amplitude = max - min (medida de dispersao mais simples, mas menos robusta).","resposta":""},
  {"id":"4312","tipo":"multipla","disciplina":"Matematica","tema":"Probabilidade","subtema":"Regra de adicao","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Se P(A) = 0,4 e P(B) = 0,3 e os eventos sao mutuamente exclusivos, entao P(A ou B) e:","alternativa_a":"0,7","alternativa_b":"0,12","alternativa_c":"0,1","alternativa_d":"1","alternativa_e":"0,5","resposta_correta":"a","explicacao":"Para eventos mutuamente exclusivos (nao podem ocorrer juntos): P(A ou B) = P(A) + P(B) = 0,4 + 0,3 = 0,7. Se nao fossem exclusivos: P(A ou B) = P(A) + P(B) - P(A e B).","resposta":""},
  {"id":"4313","tipo":"multipla","disciplina":"Matematica","tema":"Geometria Espacial","subtema":"Tronco de cone","dificuldade":"Dificil","fonte":"Vestibular","ano":"2024","enunciado":"O volume de um paralelepipedo retangular de dimensoes 3, 4 e 5 cm e:","alternativa_a":"60 cm3","alternativa_b":"47 cm3","alternativa_c":"94 cm3","alternativa_d":"20 cm3","alternativa_e":"12 cm3","resposta_correta":"a","explicacao":"Volume do paralelepipedo (caixa retangular) = comprimento x largura x altura = 3 x 4 x 5 = 60 cm3.","resposta":""},
  {"id":"4314","tipo":"multipla","disciplina":"Fisica","tema":"Mecanica","subtema":"Quantidade de movimento","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"A quantidade de movimento (momento linear) de um objeto de 3 kg movendo-se a 4 m/s e:","alternativa_a":"12 kg.m/s","alternativa_b":"7 kg.m/s","alternativa_c":"1,33 m/s","alternativa_d":"48 kg.m/s","alternativa_e":"12 N","resposta_correta":"a","explicacao":"p = m x v = 3 x 4 = 12 kg.m/s. O impulso (J = F x Delta_t) e igual a variacao do momento: J = Delta_p.","resposta":""},
  {"id":"4315","tipo":"multipla","disciplina":"Fisica","tema":"Mecanica","subtema":"Centro de massa","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"O Centro de Massa de um sistema e o ponto onde:","alternativa_a":"Toda a massa do sistema pode ser considerada concentrada para fins de movimentos translacionais","alternativa_b":"A velocidade do sistema e sempre zero","alternativa_c":"A aceleracao e maxima","alternativa_d":"As forcas internas se anulam","alternativa_e":"A energia cinetica e maxima","resposta_correta":"a","explicacao":"O Centro de Massa (CM) e o ponto medio ponderado pelas massas de um sistema. Para fins de translacao, todo o sistema se comporta como se toda a massa estivesse no CM sujeita a resultante das forcas externas. A segunda lei de Newton para o sistema: F_ext = M_total x a_CM. Isso simplifica enormemente a analise de sistemas de particulas e corpos rigidos.","resposta":""},
  {"id":"4316","tipo":"multipla","disciplina":"Fisica","tema":"Eletricidade","subtema":"Resistencia eletrica","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"A resistencia eletrica de um condutor depende de:","alternativa_a":"Comprimento, area da secao transversal e resistividade do material","alternativa_b":"Apenas da corrente eletrica","alternativa_c":"Apenas da tensao aplicada","alternativa_d":"Apenas da temperatura","alternativa_e":"Da cor do condutor","resposta_correta":"a","explicacao":"R = rho * L / A, onde rho = resistividade do material (propriedade intrinseca), L = comprimento do fio, A = area da seccao transversal. Condutor mais longo: maior R. Seccao maior: menor R (mais 'espaco' para os eletrons). Resistividade depende do material e da temperatura (resistencia aumenta com temperatura nos metais).","resposta":""},
  {"id":"4317","tipo":"multipla","disciplina":"Fisica","tema":"Eletricidade","subtema":"Circuito serie","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Em um circuito serie, a resistencia equivalente e:","alternativa_a":"A soma das resistencias individuais: Req = R1 + R2 + R3 + ...","alternativa_b":"A media das resistencias","alternativa_c":"Igual a menor resistencia","alternativa_d":"1/(1/R1 + 1/R2 + ...)","alternativa_e":"Zero","resposta_correta":"a","explicacao":"Em serie: Req = R1 + R2 + R3 + ... A corrente e a mesma em todos os elementos; a tensao total se distribui entre os elementos. Em paralelo: 1/Req = 1/R1 + 1/R2 + ... A tensao e a mesma em todos os elementos; a corrente total se distribui entre os ramos.","resposta":""},
  {"id":"4318","tipo":"multipla","disciplina":"Quimica","tema":"Quimica Geral","subtema":"Numero de Avogadro","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"O numero de Avogadro (NA = 6,02 x 10^23) representa:","alternativa_a":"O numero de particulas (atomos, moleculas ou ions) contidas em 1 mol de qualquer substancia","alternativa_b":"A massa molar em gramas de qualquer substancia","alternativa_c":"O volume molar dos gases em CNTP","alternativa_d":"O numero de eletrons no atomo mais pesado","alternativa_e":"A constante de Planck","resposta_correta":"a","explicacao":"O numero de Avogadro (NA = 6,022 x 10^23 mol^-1) e o numero de entidades elementares (atomos, moleculas, ions, eletrons) em 1 mol. 1 mol de qualquer gas em CNTP (0graus C, 1 atm) ocupa 22,4 L (volume molar). 1 mol de C-12 pesa exatamente 12 g. A constante de Boltzmann k = R/NA.","resposta":""},
  {"id":"4319","tipo":"multipla","disciplina":"Quimica","tema":"Quimica Organica","subtema":"Benzeno e derivados","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"O acido acetilsalicilico (AAS), principio ativo da aspirina, pertence ao grupo dos:","alternativa_a":"Esteres aromaticos — formado pela acetilacao do acido salicilico","alternativa_b":"Alcaloides","alternativa_c":"Terpenoides","alternativa_d":"Amino acids","alternativa_e":"Polissacarideos","resposta_correta":"a","explicacao":"O AAS (acido 2-acetoxibenzoico) e um ester formado pela reacao do acido salicilico com anidrido acetico (acetilaçao). Pertence aos anti-inflamatorios nao-esteroidais (AINE). Felix Hoffman sintetizou-o em 1897 para a Bayer. Inibe a ciclooxigenase (COX-1 e COX-2), enzima da sintese de prostaglandinas (dor e inflamacao), e tem efeito anticoagulante.","resposta":""},
  {"id":"4320","tipo":"multipla","disciplina":"Quimica","tema":"Quimica Geral","subtema":"Velocidade das reacoes","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Um catalisador aumenta a velocidade de uma reacao quimica ao:","alternativa_a":"Diminuir a energia de ativacao da reacao sem ser consumido no processo","alternativa_b":"Aumentar a temperatura do sistema","alternativa_c":"Aumentar a concentracao dos reagentes","alternativa_d":"Ser consumido para formar os produtos","alternativa_e":"Alterar o equilibrio quimico para a direita","resposta_correta":"a","explicacao":"O catalisador oferece um caminho alternativo de menor energia de ativacao para a reacao. Assim, mais moleculas tem energia suficiente para reagir (maior fator exponencial na equacao de Arrhenius), aumentando a velocidade. O catalisador nao e consumido (regenerado ao final) e nao altera a variacao de entalpia (DeltaH) nem a posicao do equilibrio (apenas acelera a chegada ao equilibrio).","resposta":""},
  {"id":"4321","tipo":"multipla","disciplina":"Biologia","tema":"Fisiologia Humana","subtema":"Sistema nervoso central","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"As meninges sao membranas que envolvem o sistema nervoso central. A inflamacao das meninges e chamada de:","alternativa_a":"Meningite — geralmente causada por bacterias ou virus","alternativa_b":"Encefalite","alternativa_c":"Poliomielite","alternativa_d":"Neuropatia","alternativa_e":"Esclerose","resposta_correta":"a","explicacao":"As meninges (dura-mater, aracnoide, pia-mater) protegem o encefalo e a medula espinhal. A meningite (inflamacao das meninges) pode ser bacteriana (meningococo — grave), viral (mais comum e menos grave) ou fungica. Sintomas: rigidez de nuca, febre, fotofobia, cefaleia intensa. A vacina meningococica protege contra os principais sorotipos bacterianos.","resposta":""},
  {"id":"4322","tipo":"multipla","disciplina":"Biologia","tema":"Fisiologia Humana","subtema":"Sistema reprodutor feminino","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"A ovulacao, liberacao do ovulo pelo ovario, ocorre normalmente:","alternativa_a":"Ao redor do 14o dia do ciclo menstrual (ciclo de 28 dias)","alternativa_b":"No inicio do ciclo (menstruacao)","alternativa_c":"No final do ciclo","alternativa_d":"A qualquer momento do ciclo","alternativa_e":"Apenas durante a gestacao","resposta_correta":"a","explicacao":"O ciclo menstrual tem ~28 dias. A fase folicular (dias 1-13): estrogênio sobe, folículo cresce. Por volta do dia 14, o pico de LH (hormonio luteinizante) desencadeia a ovulacao. A fase luteal (dias 15-28): corpo luteo produz progesterona. Se nao houver fecundacao, o corpo luteo regride, os hormonios caem e ocorre a menstruacao (~dia 28).","resposta":""},
  {"id":"4323","tipo":"multipla","disciplina":"Biologia","tema":"Botanica","subtema":"Angiospermas — frutos e sementes","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"O fruto e botanicamente definido como:","alternativa_a":"O ovario maduro (apos fecundacao), que contem e protege as sementes","alternativa_b":"Qualquer estrutura carnosa e doce das plantas","alternativa_c":"A flor apos a polinizacao","alternativa_d":"As folhas modificadas das angiospermas","alternativa_e":"O gameta feminino da planta","resposta_correta":"a","explicacao":"Botanicamente, fruto = ovario maduro (apos a dupla fecundacao). A parede do ovario (pericarpo) pode ser carnosa (frutos verdadeiros: manga, laranja) ou seca (legumes: feijao, amendoim). Pseudofrutos tem contribuicao de outras partes da flor (maca = receptaculo; morango = receptaculo; caju = pedunculo). A semente = ovulo fecundado maduro.","resposta":""},
  {"id":"4324","tipo":"multipla","disciplina":"Historia","tema":"Historia Geral","subtema":"Cruzadas","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"As Cruzadas (seculos XI-XIII) foram expediciones militares dos cristãos europeus com objetivo de:","alternativa_a":"Reconquistar a Terra Santa (Jerusalem) dos muçulmanos, embora tambem tivessem motivacoes economicas e politicas","alternativa_b":"Expandir o comercio com o Oriente Medio","alternativa_c":"Converter os povos africanos ao cristianismo","alternativa_d":"Combater a heresia catara na Franca","alternativa_e":"Estabelecer colonias no leste europeu","resposta_correta":"a","explicacao":"As Cruzadas (1095-1291), convocadas pelo papa Urbano II, tinham motivacoes multifacetadas: (1) Religiosidade medieval — reconquistar Jerusalem e os lugares sagrados dos turcos seldjucidas; (2) Economica — abertura das rotas comerciais com o Oriente, saque de cidades ricas; (3) Politica — desviar a violencia dos cavaleiros europeus para fora. Tiveram impactos enormes no contato entre culturas cristas, islamicas e judaicas.","resposta":""},
  {"id":"4325","tipo":"multipla","disciplina":"Historia","tema":"Historia Geral","subtema":"Revolucao industrial Segunda","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"A Segunda Revolucao Industrial (1870-1914) diferenciou-se da Primeira por:","alternativa_a":"Uso de eletricidade, petroleo e quimica industrial; novos paises (EUA, Alemanha, Japao) como lideres","alternativa_b":"Ser liderada exclusivamente pela Inglaterra com carvao e vapor","alternativa_c":"Nao envolver producao em massa","alternativa_d":"Ter ocorrido principalmente na America Latina","alternativa_e":"Basear-se na energia nuclear","resposta_correta":"a","explicacao":"A 2a Revolucao Industrial (1870-1914) caracterizou-se por: (1) Novas fontes de energia: eletricidade (Edison, Tesla) e petroleo (motor a combustao interna); (2) Novos materiais: aco (Bessemer), aluminio, plastico; (3) Quimica: corantes, medicamentos, fertilizantes; (4) Comunicacoes: telegrafo, telefone; (5) Novos lideres: EUA, Alemanha e Japao superaram a Inglaterra. Base do imperialismo do fim do seculo XIX.","resposta":""},
  {"id":"4326","tipo":"multipla","disciplina":"Historia","tema":"Historia do Brasil","subtema":"Crise de 1929","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"A Crise de 1929 (Grande Depressao) afetou o Brasil principalmente pela:","alternativa_a":"Queda do preco do cafe e destruicao de estoques, prejudicando a oligarquia cafeicultora paulista","alternativa_b":"Falencia dos bancos brasileiros","alternativa_c":"Invasao militar estrangeira","alternativa_d":"Colapso da industria brasileira","alternativa_e":"Hiperinflacao sem precedentes","resposta_correta":"a","explicacao":"A Crise de 1929 derrubou o preco do cafe (principal produto de exportacao brasileiro) de US$ 22,5 para US$ 8 por saca. O governo brasileiro comprou e destruiu enormes estoques de cafe para manter os precos. A oligarquia cafeicultora ficou enfraquecida, contribuindo para a crise politica que levou a Revolucao de 1930 e a ascensao de Vargas.","resposta":""},
  {"id":"4327","tipo":"multipla","disciplina":"Historia","tema":"Historia Geral","subtema":"Organizacoes regionais","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"A Uniao Europeia (UE) foi formalmente criada pelo:","alternativa_a":"Tratado de Maastricht (1992), que aprofundou a integracao europeia e criou o Euro","alternativa_b":"Tratado de Roma (1957), que criou a CEE","alternativa_c":"Acordo de Schengen (1985)","alternativa_d":"Tratado de Lisboa (2009)","alternativa_e":"Tratado de Versalhes (1919)","resposta_correta":"a","explicacao":"O Tratado de Maastricht (1992, Holanda) transformou a CEE (Comunidade Economica Europeia) em Uniao Europeia, aprofundando a integracao: criou a cidadania europeia, estabeleceu criterios para o Euro (adotado em 1999/2002) e expandiu cooperacao em politica externa e justicia. O processo de integracao europeia comecou com o Tratado de Roma (1957) e continua evoluindo.","resposta":""},
  {"id":"4328","tipo":"multipla","disciplina":"Historia","tema":"Historia Geral","subtema":"Imperio Romano","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"A queda do Imperio Romano do Ocidente (476 d.C.) e utilizada como marco da transicao entre:","alternativa_a":"Antiguidade e Idade Media","alternativa_b":"Preistoria e Antiguidade","alternativa_c":"Idade Media e Modernidade","alternativa_d":"Modernidade e Contemporaneidade","alternativa_e":"Paleolitico e Mesolitico","resposta_correta":"a","explicacao":"A historiografia tradicional divide a historia em: Pre-historia (ate escrita, ~3500 a.C.), Antiguidade (3500 a.C. - 476 d.C.), Idade Media (476-1453), Modernidade (1453-1789) e Contemporaneidade (1789-presente). A queda de Roma em 476 d.C. (invasao germânica) marca o inicio da Idade Media. A queda de Constantinopla em 1453 (Imperio Romano do Oriente) marca a transicao para a Modernidade.","resposta":""},
  {"id":"4329","tipo":"multipla","disciplina":"Geografia","tema":"Geologia","subtema":"Rochas","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"As rochas igneas (magmaticas) se formam pelo:","alternativa_a":"Resfriamento e solidificacao do magma — intrusivas (plutonicas) ou extrusivas (vulcanicas)","alternativa_b":"Deposito de sedimentos compactados","alternativa_c":"Transformacao de rochas preexistentes por calor e pressao","alternativa_d":"Deposito de sais minerais em aguas marinhas","alternativa_e":"Atividade biologica de organismos","resposta_correta":"a","explicacao":"Rochas igneas (magmaticas): formadas pela solidificacao do magma. Intrusivas (plutonicas): solidificam lentamente no interior da crosta — granito, diorito (cristais grandes). Extrusivas (vulcanicas): solidificam rapidamente na superficie — basalto, obsidiana (cristais finos ou amorfos). Rochas sedimentares: deposito e cimentacao de sedimentos. Rochas metamorficas: transformacao por calor e pressao (marmore = calcario metamorfizado).","resposta":""},
  {"id":"4330","tipo":"multipla","disciplina":"Lingua Portuguesa","tema":"Semantica","subtema":"Denotacao e conotacao","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"No verso 'O mar e um cachorro enorme', a palavra 'cachorro' e usada em sentido:","alternativa_a":"Conotativo — evoca agitacao, barulho, imprevisibilidade","alternativa_b":"Denotativo — descreve um animal de estimacao","alternativa_c":"Tecnico","alternativa_d":"Juridico","alternativa_e":"Nenhum dos anteriores","resposta_correta":"a","explicacao":"Denotacao: sentido literal, dicionarizado. 'Cachorro' denotativo = o animal. Conotacao: sentido figurado, contextual. 'O mar e um cachorro enorme' = metafora que evoca a natureza agitada, barulhenta e imprevisível do mar. A conotacao enriquece o texto literario com camadas de significado. O mesmo objeto pode ter muitas conotacoes dependendo do contexto cultural.","resposta":""},
  {"id":"4331","tipo":"multipla","disciplina":"Lingua Portuguesa","tema":"Gramatica","subtema":"Derivacao prefixal","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"A palavra 'irreal' e formada pelo processo de:","alternativa_a":"Derivacao prefixal — prefixo 'ir-' (variante de 'in-') + real","alternativa_b":"Composicao","alternativa_c":"Derivacao sufixal","alternativa_d":"Hibridismo","alternativa_e":"Onomatopeia","resposta_correta":"a","explicacao":"Derivacao prefixal: adicao de prefixo a uma palavra base. 'Ir-' e uma variante do prefixo latino 'in-' (negacao) antes de radicais que comecam com 'r': in-real = irreal (assimilacao). Outros prefixos: des- (desfazer), re- (refazer), anti- (antiviral), pre- (pre-natal). Derivacao sufixal: adicao de sufixo: real-idad-e. Composicao: uni-versidade, pas-te-l-aria.","resposta":""},
  {"id":"4332","tipo":"multipla","disciplina":"Lingua Portuguesa","tema":"Literatura Brasileira","subtema":"Haroldo de Campos","dificuldade":"Dificil","fonte":"Vestibular","ano":"2024","enunciado":"O Concretismo (Poesia Concreta), movimento liderado por Augusto de Campos, Haroldo de Campos e Decio Pignatari nos anos 1950, propunha:","alternativa_a":"A poesia como objeto visual e sonoro — exploracao grafica, espacial e fonetica do poema","alternativa_b":"O retorno ao verso metrificado tradicional","alternativa_c":"A poesia comprometida com a luta social","alternativa_d":"O verso livre romantizado","alternativa_e":"A poesia regional nordestina","resposta_correta":"a","explicacao":"O Concretismo (manifesto inaugurado com 'Plano-Piloto para Poesia Concreta', 1958) propunha a 'poesia-objeto': o poema explorava o espaco grafico da pagina, a musicalidade, o visual e a estrutura linguistica como material poetico. Influenciado por Mallarme, e. e. cummings e pela semiologia. Palavras dispostas no espaco da pagina criam significados visuais alem do linguistico. Foi o movimento de vanguarda mais internacionalmente conhecido do Brasil.","resposta":""},
  {"id":"4333","tipo":"multipla","disciplina":"Filosofia","tema":"Filosofia da Historia","subtema":"Hegel","dificuldade":"Dificil","fonte":"Vestibular","ano":"2024","enunciado":"Para Hegel, a historia se desenvolve pela:","alternativa_a":"Dialética de tese, antitese e sintese — o Espirito Absoluto se realiza progressivamente","alternativa_b":"Forcas materiais e relacoes de producao","alternativa_c":"Vontade de poder dos individuos extraordinarios","alternativa_d":"Ciclos repetitivos sem progressao","alternativa_e":"Ordem divina providencial","resposta_correta":"a","explicacao":"O idealismo historico de Hegel: a historia e o processo de autoconhecimento do Espirito Absoluto (Geist). O movimento e dialetico: toda realidade (tese) gera sua negacao (antitese) que e superada numa sintese superior. A historia progride em direcao a maior liberdade e autoconsciencia. Marx inverteu Hegel: para Marx, nao e o Espirito mas as forcas materiais (modo de producao) que movem a historia.","resposta":""},
  {"id":"4334","tipo":"multipla","disciplina":"Filosofia","tema":"Filosofia Contemporanea","subtema":"Desconstrucao","dificuldade":"Dificil","fonte":"Vestibular","ano":"2024","enunciado":"A desconstrucao de Jacques Derrida propoe que os textos:","alternativa_a":"Contem contradicoes e hirarquias que podem ser subvertidas — o significado e sempre diferido e instavel","alternativa_b":"Tem um significado fixo e definitivo estabelecido pelo autor","alternativa_c":"Devem ser interpretados pela intencao original do escritor","alternativa_d":"Sao representacoes neutras da realidade","alternativa_e":"Tem hierarquias estables e bem definidas","resposta_correta":"a","explicacao":"Derrida propoe a 'desconstrucao' como estrategia de leitura: todo texto contem hirarquias de oposicoes binarias (fala/escrita, presenca/ausencia, homem/mulher) que favorecem um termo sobre o outro. A desconstrucao mostra como essas hierarquias sao artificiais e como o texto subverte suas proprias pretensoes de estabilidade. O significado nunca e pleno — e sempre 'differance' (diferenca e diferimento).","resposta":""},
  {"id":"4335","tipo":"multipla","disciplina":"Sociologia","tema":"Sociologia da Globalizacao","subtema":"Fluxos globais","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Arjun Appadurai analisa a globalizacao por meio de cinco 'paisagens' (scapes). Ethnoscapes refere-se a:","alternativa_a":"Fluxos globais de pessoas — migrantes, turistas, refugiados e trabalhadores que circulam pelo mundo","alternativa_b":"Fluxo de tecnologias atraves das fronteiras","alternativa_c":"Fluxo de capital financeiro global","alternativa_d":"Fluxo de imagens e midias","alternativa_e":"Fluxo de ideologias politicas","resposta_correta":"a","explicacao":"Appadurai ('Modernity at Large', 1996) propoe cinco dimensoes dos fluxos culturais globais: (1) Ethnoscapes: fluxo de pessoas (migrantes, refugiados, diaspora); (2) Technoscapes: tecnologias; (3) Financescapes: capital; (4) Mediascapes: imagens e narrativas midiaticas; (5) Ideoscapes: ideologias e conceitos politicos. Esses fluxos sao disjuntos e geram a cultura global hibrida.","resposta":""},
  {"id":"4336","tipo":"multipla","disciplina":"Sociologia","tema":"Sociologia da Modernidade","subtema":"Reflexividade","dificuldade":"Dificil","fonte":"Vestibular","ano":"2024","enunciado":"Anthony Giddens caracteriza a modernidade tardia pela 'reflexividade', que significa:","alternativa_a":"O conhecimento e as praticas sociais sao constantemente revistos e modificados a luz de novas informacoes","alternativa_b":"A populacao reflete apenas sobre o passado","alternativa_c":"As ciencias sociais nao produzem conhecimento confiavel","alternativa_d":"A sociedade e determinada por forcas inconscientes","alternativa_e":"A tradicao substitui a razao nas sociedades modernas","resposta_correta":"a","explicacao":"Giddens, em 'As Consequencias da Modernidade' (1990), propoe que a reflexividade e uma caracteristica central da modernidade: o conhecimento sobre a sociedade (incluindo a ciencia social) circula de volta para a sociedade e modifica seu comportamento. Nao ha ponto de Arquimedes externo — o conhecimento e constantemente revisado. Isso produz insegurança ontologica (o mundo e imprevisivel) mas tambem potencial emancipatorio.","resposta":""},
  {"id":"4337","tipo":"multipla","disciplina":"Matematica","tema":"Numeros","subtema":"Numeros reais e irracionais","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"O numero raiz(2) e:","alternativa_a":"Irracional — nao pode ser expresso como fracao de inteiros","alternativa_b":"Racional com decimal finito","alternativa_c":"Inteiro","alternativa_d":"Complexo","alternativa_e":"Natural","resposta_correta":"a","explicacao":"raiz(2) e um numero irracional: sua representacao decimal e infinita e nao-periodica (~1,41421356...). A prova e classica: suponha que raiz(2) = p/q (frac irredutivel). Entao 2 = p^2/q^2, logo p^2 = 2q^2. P e par, digamos p=2k. Entao 4k^2 = 2q^2, q^2 = 2k^2 — q tambem e par, contradizendo a irredutibilidade. Prova por contradicao dos pitagoricos.","resposta":""},
  {"id":"4338","tipo":"multipla","disciplina":"Matematica","tema":"Geometria Plana","subtema":"Triangulo equilatero","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"Um triangulo equilatero tem todos os angulos iguais a:","alternativa_a":"60 graus","alternativa_b":"90 graus","alternativa_c":"45 graus","alternativa_d":"120 graus","alternativa_e":"30 graus","resposta_correta":"a","explicacao":"Em um triangulo equilatero, todos os tres lados sao iguais e todos os tres angulos sao iguais. Soma dos angulos internos = 180 graus / 3 = 60 graus cada.","resposta":""},
  {"id":"4339","tipo":"multipla","disciplina":"Matematica","tema":"Funcoes","subtema":"Zeros da funcao","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"O zero (raiz) de f(x) = 3x - 6 e:","alternativa_a":"x = 2","alternativa_b":"x = 6","alternativa_c":"x = 3","alternativa_d":"x = -2","alternativa_e":"x = 1/2","resposta_correta":"a","explicacao":"f(x) = 0 => 3x - 6 = 0 => 3x = 6 => x = 2.","resposta":""},
  {"id":"4340","tipo":"multipla","disciplina":"Fisica","tema":"Mecanica","subtema":"Lancamento vertical","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Uma pedra e lancada verticalmente para cima com velocidade inicial de 20 m/s. A altura maxima atingida (g=10 m/s2) e:","alternativa_a":"20 m","alternativa_b":"40 m","alternativa_c":"200 m","alternativa_d":"10 m","alternativa_e":"4 m","resposta_correta":"a","explicacao":"Na altura maxima, v = 0. Equacao de Torricelli: v^2 = v0^2 - 2gh => 0 = 400 - 20h => h = 400/20 = 20 m.","resposta":""},
  {"id":"4341","tipo":"multipla","disciplina":"Fisica","tema":"Eletricidade","subtema":"Transformacoes de energia","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"Numa lampada incandescente, a energia eletrica e convertida principalmente em:","alternativa_a":"Calor e luz (a maior parte e calor — baixa eficiencia)","alternativa_b":"Energia cinetica","alternativa_c":"Energia potencial","alternativa_d":"Energia quimica","alternativa_e":"Energia nuclear","resposta_correta":"a","explicacao":"Na lampada incandescente, a corrente aquece o filamento de tungstênio ate ~2500K (incandescencia). Apenas ~5-10% da energia eletrica e convertida em luz visivel; o restante e emitido como calor (infravermelho). Por isso as lampadas incandescentes foram substituidas por fluorescentes (~25% de eficiencia) e LEDs (~50% de eficiencia).","resposta":""},
  {"id":"4342","tipo":"multipla","disciplina":"Quimica","tema":"Quimica Geral","subtema":"Reacoes organicas em cotidiano","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"O vinagre e uma solucao aquosa de:","alternativa_a":"Acido acetico (CH3COOH) a ~5%","alternativa_b":"Acido cloridrico","alternativa_c":"Acido sulfurico","alternativa_d":"Alcool etilico","alternativa_e":"Acido lactico","resposta_correta":"a","explicacao":"O vinagre e produzido pela oxidacao do alcool etilico (fermentacao acetica): C2H5OH + O2 -> CH3COOH + H2O. Contem ~5% de acido acetico. E utilizado na culinaria como condimento e conservante. O acido acetico e um acido carboxilico de dois carbonos (acido etanoico), com pH ~2,4.","resposta":""},
  {"id":"4343","tipo":"multipla","disciplina":"Biologia","tema":"Fisiologia Humana","subtema":"Doencas cardiovasculares","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"A arteriosclerose e o endurecimento das arterias causado principalmente pelo:","alternativa_a":"Acumulo de placas de ateroma (colesterol LDL, calcio e celulas inflamatorias) na parede arterial","alternativa_b":"Bacterias na corrente sanguinea","alternativa_c":"Excesso de potassio na dieta","alternativa_d":"Deficiencia de vitamina C","alternativa_e":"Virus que atacam as celulas endoteliais","resposta_correta":"a","explicacao":"A aterosclerose e uma doenca inflamatorio-degenerativa das arterias: deposito de gordura (principalmente LDL oxidado), celulas inflamatorias e calcio formam placas de ateroma que estreitam e endurecem as arterias. Fatores de risco: hipertensao, diabetes, tabagismo, obesidade, dieta rica em gordura saturada, sedentarismo. Complicacoes: infarto do miocardio, AVC, insuficiencia renal.","resposta":""},
  {"id":"4344","tipo":"multipla","disciplina":"Biologia","tema":"Ecologia","subtema":"Poluicao do ar","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"A chuva acida e causada principalmente pela emissao de:","alternativa_a":"SO2 (dioxido de enxofre) e NOx (oxidos de nitrogenio) por industrias e veiculos","alternativa_b":"CO2 de queimadas na Amazonia","alternativa_c":"Metano de aterros sanitarios","alternativa_d":"CFCs de equipamentos de refrigeracao","alternativa_e":"Vapor d'agua de usinas termoeletricas","resposta_correta":"a","explicacao":"A chuva acida forma-se quando SO2 (queima de carvao com enxofre) e NOx (motores a combustao) reagem com a agua atmosferica formando acidos (H2SO4 e HNO3). O pH pode cair para 3-4 (normal: 5,6). Afeta lagos (acidificacao, morte de peixes), florestas (lixivacao de nutrientes, morte de arvores), monumentos (corrosao de pedra calcaria) e saude humana.","resposta":""},
  {"id":"4345","tipo":"multipla","disciplina":"Historia","tema":"Historia do Brasil","subtema":"Escravidao indigena","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"A escravidao indigena no Brasil colonial foi combatida principalmente pelos:","alternativa_a":"Jesuitas — que propugnavam a catequizacao e protecao dos indigenas, em conflito com os colonos","alternativa_b":"Governo da Coroa portuguesa desde o inicio","alternativa_c":"Comerciantes holandeses","alternativa_d":"Proprios colonos escravistas","alternativa_e":"Tropas mercenarias indigenas","resposta_correta":"a","explicacao":"Os jesuitas (Companhia de Jesus, fundada por Inacio de Loyola) chegaram ao Brasil em 1549 e criaram as missoes indigenas (reducoes), onde catequizavam e protegiam os indigenas do trabalho forcado. Isso gerou conflito constante com os colonos, que queriam mao de obra indigena. O marques de Pombal expulsou os jesuitas do Brasil e de todas as colonias portuguesas em 1759.","resposta":""},
  {"id":"4346","tipo":"multipla","disciplina":"Historia","tema":"Historia Geral","subtema":"Liga das Nacoes","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"A Liga das Nacoes, criada apos a Primeira Guerra Mundial, fracassou principalmente por:","alternativa_a":"Nao ter adesao dos EUA, nao ter forcas militares proprias e fracassar em conter as agressoes do Eixo","alternativa_b":"Ter sido destruida na Segunda Guerra","alternativa_c":"Ter excluido a Alemanha de qualquer participacao","alternativa_d":"Ser dominada pela URSS","alternativa_e":"Nao ter incluido o Brasil como membro","resposta_correta":"a","explicacao":"A Liga das Nacoes (1920-1946), proposta por Woodrow Wilson (14 pontos), foi criada pelo Tratado de Versalhes. Fracassos: (1) O Senado americano recusou a adesao dos EUA (isolacionismo); (2) Sem forca militar, nao podia coagir estados; (3) Falhou em conter a invasao da Manchuria pelo Japao (1931), da Etiopia pela Italia (1935-36) e a expansao da Alemanha nazista. Foi sucedida pela ONU em 1945.","resposta":""},
  {"id":"4347","tipo":"multipla","disciplina":"Historia","tema":"Historia do Brasil","subtema":"Ditadura — Milagre Economico","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"O 'milagre economico' brasileiro (1968-1973) caracterizou-se por:","alternativa_a":"Alto crescimento do PIB (~10% ao ano), mas com concentracao de renda e aumento da desigualdade","alternativa_b":"Crescimento igualitario com distribuicao de renda","alternativa_c":"Industrializacao sem endividamento externo","alternativa_d":"Crescimento baseado na reforma agraria","alternativa_e":"Autonomia tecnologica completa","resposta_correta":"a","explicacao":"O milagre economico (governo Medici) teve crescimento medio do PIB de ~11%/ano, impulsionado por: capital externo (endividamento), petroleo barato, exportacoes diversificadas, grandes obras (BR-1, Itaipu, Angra). A contrapartida: concentracao de renda (os ricos ficaram mais ricos), repracao politica (silenciou criticas com crescimento), endividamento externo que gerou a crise dos anos 1980.","resposta":""},
  {"id":"4348","tipo":"multipla","disciplina":"Historia","tema":"Historia do Brasil","subtema":"Diretas Ja","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"O movimento 'Diretas Ja' (1983-1984) foi uma campanha popular que exigia:","alternativa_a":"Eleicoes diretas para presidente da Republica, encerrando as eleicoes indiretas da ditadura","alternativa_b":"A anistia de presos politicos","alternativa_c":"A convocacao de uma Constituinte","alternativa_d":"O fim do regime militar imediato","alternativa_e":"Reducao da jornada de trabalho","resposta_correta":"a","explicacao":"A campanha Diretas Ja mobilizou milhoes de brasileiros em comícios em todo o pais (o maior em SP com 1,7 mi de pessoas, 16/04/1984) pela aprovacao da Emenda Dante de Oliveira, que previa eleicoes diretas para presidente. A emenda foi derrotada no Congresso em abril de 1984. A transicao ocorreu indiretamente: Tancredo Neves foi eleito pelo Colegio Eleitoral (jan. 1985), mas morreu antes de tomar posse; Jose Sarney assumiu.","resposta":""},
  {"id":"4349","tipo":"multipla","disciplina":"Geografia","tema":"Economia","subtema":"Subdesenvolvimento","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"A teoria da dependencia, desenvolvida por economistas latino-americanos como Cardoso e Faletto, argumenta que:","alternativa_a":"O subdesenvolvimento e estrutural — paises perifericos se especializam em produtos primarios e transferem valor para o centro","alternativa_b":"O subdesenvolvimento e culpa do Estado interventor","alternativa_c":"O livre-mercado e a solucao para o subdesenvolvimento","alternativa_d":"A industrializacao sempre resolve o subdesenvolvimento","alternativa_e":"A dependencia e causada apenas por fatores internos","resposta_correta":"a","explicacao":"A teoria da dependencia (CEPAL, Prebisch, Cardoso, Faletto, Frank) critica o liberalismo classico: a relacao centro-periferia e estruturalmente desigual. Paises perifericos exportam commodities de baixo valor agregado e importam manufaturados de alto valor — deterioracao dos termos de troca. O capital externo, ao inves de desenvolver, extrai excedente. A solucao proposta variava: industrializacao protegida (CEPAL) ou transformacao social radical (correntes mais radicais).","resposta":""},
  {"id":"4350","tipo":"multipla","disciplina":"Lingua Portuguesa","tema":"Gramatica","subtema":"Verbos irregulares","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"O imperfeito do subjuntivo de 'ser' na 1a pessoa do singular e:","alternativa_a":"fosse","alternativa_b":"seria","alternativa_c":"serei","alternativa_d":"foi","alternativa_e":"sou","resposta_correta":"a","explicacao":"Conjugacao de 'ser' no imperfeito do subjuntivo: fosse, fosses, fosse, fossemos, fosseis, fossem. O imperfeito do subjuntivo e formado a partir da 3a pessoa do plural do preterito perfeito do indicativo (foram) menos a desinencia -am + terminacoes (-se, -sses, -sse, -ssemos, -sseis, -ssem). Usado em orações condicionais (se fosse, se tivesse), concessivas e em construcoes como 'caso fosse'.","resposta":""},
  {"id":"4351","tipo":"multipla","disciplina":"Lingua Portuguesa","tema":"Literatura Brasileira","subtema":"Poesia concreta","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"O Tropicalismo (1967-1969), movimento cultural brasileiro, caracterizou-se por:","alternativa_a":"Mistura de musica popular brasileira com rock, vanguardas artisticas e critica politica — Caetano Veloso e Gilberto Gil","alternativa_b":"Retorno ao nacionalismo musical puro","alternativa_c":"Exclusao de elementos estrangeiros da cultura brasileira","alternativa_d":"Musica classica erudita de camara","alternativa_e":"Renovacao do chorinho tradicional","resposta_correta":"a","explicacao":"O Tropicalismo (ou Tropicalia) foi um movimento cultural liderado por Caetano Veloso e Gilberto Gil (com participacao de Tom Ze, Gal Costa, Os Mutantes). Misturava musica regional brasileira com rock e psicodelia, incorporando a estetica pop e vanguardas artisticas. Era uma critica ironica ao Brasil — tanto ao conservadorismo quanto ao nacionalismo da esquerda. Influenciado por Oswald de Andrade, Cinema Novo e artes plasticas (Helio Oiticica).","resposta":""},
  {"id":"4352","tipo":"multipla","disciplina":"Filosofia","tema":"Etica","subtema":"Etica ambiental","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"A etica ambiental profunda (Deep Ecology), proposta por Arne Naess, defende que:","alternativa_a":"Todos os seres vivos tem valor intrinseco, independente de sua utilidade para o ser humano","alternativa_b":"A natureza deve ser preservada apenas porque e util para os humanos","alternativa_c":"So os animais domesticos tem direitos morais","alternativa_d":"O desenvolvimento economico deve prevalecer sobre a preservacao","alternativa_e":"So os humanos tem dignidade moral","resposta_correta":"a","explicacao":"A Deep Ecology (Naess, 1973) propoe uma visao biocentrica: todos os seres vivos e o proprio ecossistema tem valor intrinseco (nao apenas instrumental). Contrasta com a ecologia rasa (shallow ecology) que preserva a natureza apenas por razoes antropocentricas (recursos para humanos). A Deep Ecology exige mudanca de paradigma — do antropocentrismo para o ecocentrismo.","resposta":""},
  {"id":"4353","tipo":"multipla","disciplina":"Sociologia","tema":"Sociologia da Educacao","subtema":"Educacao bancaria","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"Paulo Freire critica a 'educacao bancaria' porque ela:","alternativa_a":"Trata o aluno como recipiente passivo de informacoes despejadas pelo professor, sem dialogo","alternativa_b":"Incentiva demasiado a participacao dos alunos","alternativa_c":"Ignora as materias tradicionais","alternativa_d":"Valoriza o conhecimento popular sobre o cientifico","alternativa_e":"Promove a alfabetizacao critica","resposta_correta":"a","explicacao":"Paulo Freire, em 'Pedagogia do Oprimido' (1968), critica a 'educacao bancaria': o professor deposita conteudo nos alunos passivos, acriticos, que memorizam e reproduzem sem questionar. Propoe a educacao dialogica: o professor e o aluno aprendem juntos, partindo da realidade vivida pelos educandos, desenvolvendo consciencia critica (conscientizacao) que leva a transformacao social. Base da pedagogia critica global.","resposta":""},
  {"id":"4354","tipo":"multipla","disciplina":"Sociologia","tema":"Sociologia do Consumo","subtema":"Sociedade de consumo","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Jean Baudrillard analisa o consumo contemporaneo como:","alternativa_a":"Consumo de signos e simbolos — as mercadorias valem pelo status e identidade que conferem, nao pelo uso","alternativa_b":"Necessidade economica de sobrevivencia","alternativa_c":"Forma de redistribuicao de riqueza","alternativa_d":"Exercicio da liberdade individual","alternativa_e":"Manifestacao da irracionalidade humana","resposta_correta":"a","explicacao":"Baudrillard ('A Sociedade de Consumo', 1970) argumenta que na sociedade pos-industrial o consumo nao e guiado pelo valor de uso (utilidade) nem pelo valor de troca (dinheiro), mas pelo valor-signo: consumimos marcas, estilos e simbolos para construir identidades e distincoes sociais. O simulacro (representacao sem referente real) substitui o real. O hiperconsumo e uma forma de controle social, nao de satisfacao de necessidades reais.","resposta":""},
  {"id":"4355","tipo":"multipla","disciplina":"Matematica","tema":"Numeros","subtema":"Divisibilidade — 9","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"O numero 4.572 e divisivel por 9 porque:","alternativa_a":"4+5+7+2 = 18, que e divisivel por 9","alternativa_b":"Termina em 2","alternativa_c":"E um numero par","alternativa_d":"E maior que 900","alternativa_e":"Tem 4 algarismos","resposta_correta":"a","explicacao":"Criterio de divisibilidade por 9: a soma dos algarismos e divisivel por 9. 4+5+7+2 = 18 = 9x2. Logo 4.572 e divisivel por 9. Verificando: 4.572 / 9 = 508.","resposta":""},
  {"id":"4356","tipo":"multipla","disciplina":"Matematica","tema":"Funcoes","subtema":"Crescimento e decrescimento","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"A funcao f(x) = 2^x e:","alternativa_a":"Crescente para todo x real (base > 1)","alternativa_b":"Decrescente para todo x","alternativa_c":"Constante","alternativa_d":"Crescente so para x > 0","alternativa_e":"Decrescente para x < 0","resposta_correta":"a","explicacao":"f(x) = a^x com a > 1 e crescente para todo x real. f(x) = a^x com 0 < a < 1 e decrescente. Para f(x) = 2^x: quando x cresce, 2^x cresce. Exemplos: f(0) = 1, f(1) = 2, f(2) = 4, f(-1) = 0,5.","resposta":""},
  {"id":"4357","tipo":"multipla","disciplina":"Matematica","tema":"Algebra","subtema":"Equacao de segundo grau discriminante","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Se o discriminante (Delta) de uma equacao de segundo grau e negativo, entao:","alternativa_a":"Nao existem raizes reais — a equacao tem duas raizes complexas conjugadas","alternativa_b":"Ha uma raiz real repetida","alternativa_c":"Ha duas raizes reais distintas","alternativa_d":"A equacao tem tres raizes","alternativa_e":"A equacao nao pode ser resolvida","resposta_correta":"a","explicacao":"Para ax^2 + bx + c = 0, Delta = b^2 - 4ac. Se Delta > 0: duas raizes reais distintas. Se Delta = 0: uma raiz real repetida. Se Delta < 0: nao ha raizes reais — ha duas raizes complexas conjugadas (a + bi e a - bi). Nos Ensinos Medio e Vestibular, trabalha-se geralmente apenas o caso dos reais.","resposta":""},
  {"id":"4358","tipo":"multipla","disciplina":"Fisica","tema":"Mecanica","subtema":"Alavancas","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"Numa alavanca em equilibrio, o Principio de Arquimedes (alavancas) estabelece que:","alternativa_a":"Forca x braco da forca = carga x braco da carga (momento de forcas)","alternativa_b":"A forca e igual a carga multiplicada pela altura","alternativa_c":"A potencia e igual ao produto de forca e velocidade","alternativa_d":"O trabalho realizado e zero","alternativa_e":"A pressao e uniforme em todos os pontos","resposta_correta":"a","explicacao":"Alavancas: a condicao de equilibrio e que a soma dos torques em relacao ao fulcro seja zero: F x d_F = C x d_C (forca x braco da forca = carga x braco da carga). Isso permite multiplicar a forca: com braco da forca maior, uma pequena forca equilibra uma grande carga. Ex: balanca, tesoura, quebra-nozes sao exemplos de alavancas.","resposta":""},
]

